const body = $json.body;
const review = body.review || body;
const flags = [];
let risk_score = 0;

// ── Rule 1: Extremely short review ──
if ((review.review_text || '').trim().length < 10) {
  flags.push('REVIEW_TOO_SHORT');
  risk_score += 30;
}

// ── Rule 2: All caps ──
if (review.review_text && review.review_text === review.review_text.toUpperCase() && review.review_text.length > 5) {
  flags.push('ALL_CAPS');
  risk_score += 20;
}

// ── Rule 3: Extreme rating with no context ──
if ((review.rating === 5 || review.rating === 1) && (review.review_text || '').trim().length < 20) {
  flags.push('EXTREME_RATING_NO_CONTEXT');
  risk_score += 25;
}

// ── Rule 4: Spam patterns ──
const spamPatterns = ['click here', 'buy now', 'discount code', 'promo', 'http', 'www.', '.com'];
const textLower = (review.review_text || '').toLowerCase();
spamPatterns.forEach(p => {
  if (textLower.includes(p)) { flags.push('SPAM_PATTERN'); risk_score += 35; }
});

// ── Rule 5: Unverified purchase ──
if (!review.verified_purchase) {
  flags.push('UNVERIFIED_PURCHASE');
  risk_score += 15;
}

const isFake   = risk_score >= 50;
const status   = isFake ? 'Quarantined' : 'Cleared';

return [{ json: { review, flags, risk_score, status, isFake } }];
